export function createDefaultConfig(): DoNotDisturbConfig {
  return {
    maxPerHour: 3,
    maxPerDay: 15,
    quietHoursStart: 23,
    quietHoursEnd: 7,
    consecutiveIgnoresForBackoff: 3,
    backoffMultiplier: 1.5,
  }
}

findings.suggestion:
Add a validated factory function that enforces invariants:

export function createDoNotDisturbConfig(params: Partial<DoNotDisturbConfig> = {}): DoNotDisturbConfig {
  const config = { ...createDefaultConfig(), ...params }
  if (config.quietHoursStart < 0 || config.quietHoursStart > 23) throw new Error('quietHoursStart must be 0-23')
  if (config.quietHoursEnd < 0 || config.quietHoursEnd > 23) throw new Error('quietHoursEnd must be 0-23')
  if (config.maxPerHour < 1) throw new Error('maxPerHour must be >= 1')
  if (config.maxPerDay < 1) throw new Error('maxPerDay must be >= 1')
  if (config.backoffMultiplier <= 1.0) throw new Error('backoffMultiplier must be > 1.0')
  return config
}

Since TypeScript cannot enforce numeric ranges at the type level without branded types, add a factory function with validation:

export function createTriggerInput(raw: TriggerInput): TriggerInput {
  if (raw.currentHour < 0 || raw.currentHour > 23) throw new Error('currentHour must be 0-23')
  if (raw.currentMinute < 0 || raw.currentMinute > 59) throw new Error('currentMinute must be 0-59')
  if (raw.continuousWorkDurationMs < 0) throw new Error('continuousWorkDurationMs must be >= 0')
  return raw
}

